section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/headroom-cost-model.json",
  "type": "object",
  "required": [
    "report_period",
    "resources",
    "alerts",
    "quarterly_projection",
    "anomalies",
    "review_date",
    "signoff"
  ],
  "properties": {
    "report_period": {
      "type": "string",
      "description": "string"
    },
    "resources": {
      "type": "array",
      "description": "array (each {name, type, provisioned, utilisation_p95_30d, headroom_pct, cost_unit_usd, monthly_cost_usd})"
    },
    "alerts": {
      "type": "array",
      "description": "array (each {resource, threshold, action})"
    },
    "quarterly_projection": {
      "type": "object",
      "description": "object (next_quarter_demand_delta_pct, next_quarter_cost_delta_usd)"
    },
    "anomalies": {
      "type": "array",
      "description": "array (each {resource, deviation_pct, investigation_ticket})"
    },
    "review_date": {
      "type": "string",
      "description": "string"
    },
    "signoff": {
      "type": "object",
      "description": "object (engineering_leader, finance, date)"
    }
  }
}
